// src/components/FormAluno.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

function FormAluno({ onNovoAluno, alunoEditando, onFimEdicao }) {
  const { user } = useAuth();
  const token = user.token;
  const headers = { Authorization: `Bearer ${token}` };

  // Campos do formulário
  const [nome, setNome] = useState('');
  const [ra, setRa] = useState('');
  const [box, setBox] = useState(''); // até 3 dígitos numéricos
  const [boxId, setBoxId] = useState(null); // id do box existente
  const [periodoId, setPeriodoId] = useState('');
  const [usuario, setUsuario] = useState('');
  const [senha, setSenha] = useState('');
  const [showSenha, setShowSenha] = useState(false);
  const [role, setRole] = useState('aluno');
  const [mensagem, setMensagem] = useState('');

  // Listas auxiliares
  const [periodos, setPeriodos] = useState([]);

  const alunoId = alunoEditando?.id;

  // Carrega períodos
  useEffect(() => {
    axios.get('/api/periodos', { headers })
      .then(res => setPeriodos(res.data))
      .catch(() => setPeriodos([]));
  }, [token]);

  // Preenche dados em edição + busca box
  useEffect(() => {
    if (alunoEditando) {
      setNome(alunoEditando.nome || '');
      setRa(alunoEditando.ra || '');
      setPeriodoId(alunoEditando.periodo_id ? String(alunoEditando.periodo_id) : '');
      setUsuario(alunoEditando.usuario || '');
      setRole(alunoEditando.role || 'aluno');
      setSenha('');
      setShowSenha(false);
      // busca box existente
      axios.get(`/api/boxes/${alunoEditando.id}`, { headers })
        .then(res => {
          if (res.data.length) {
            setBox(String(res.data[0].conteudo).slice(0,3));
            setBoxId(res.data[0].id);
          } else {
            setBox('');
            setBoxId(null);
          }
        })
        .catch(() => {
          setBox('');
          setBoxId(null);
        });
    } else {
      // limpa tudo
      setNome(''); setRa(''); setBox(''); setBoxId(null);
      setPeriodoId(''); setUsuario(''); setSenha(''); setShowSenha(false);
      setRole('aluno'); setMensagem('');
    }
  }, [alunoEditando, token]);

  const validarNomeCompleto = n => n.trim().split(' ').filter(p => p.length>=2).length>=2;
  const validarRA = r => /^\d{1,9}$/.test(r);

  const handleSubmit = e => {
    e.preventDefault();
    if (!validarNomeCompleto(nome)) return setMensagem('Informe nome completo!');
    if (!validarRA(ra)) return setMensagem('RA inválido!');
    if (!usuario.trim()) return setMensagem('Insira um usuário!');
    if (!alunoEditando && senha.length<4) return setMensagem('Senha mínimo 4 chars!');
    if (!periodoId) return setMensagem('Selecione período!');

    const alunoDados = { nome, ra, periodo_id: periodoId, usuario, senha, role };
    if (alunoEditando) {
      // editar aluno
      const payload = { ...alunoDados };
      if (!senha) delete payload.senha;
      axios.put(`/api/alunos/${alunoId}`, payload, { headers })
        .then(() => {
          // atualizar/crear box
          if (box) {
            if (boxId) {
              axios.put(`/api/boxes/${boxId}`, { conteudo: box }, { headers });
            } else {
              axios.post('/api/boxes', { aluno_id: alunoId, conteudo: box }, { headers });
            }
          }
          setMensagem('Atualizado com sucesso!');
          onNovoAluno(); onFimEdicao();
        })
        .catch(err => setMensagem(err.response?.data?.error||'Erro atualizar.'));
    } else {
      // novo aluno
      axios.post('/api/alunos', alunoDados, { headers })
        .then(res => {
          const newId = res.data.id;
          if (box) {
            axios.post('/api/boxes', { aluno_id: newId, conteudo: box }, { headers });
          }
          setMensagem('Cadastrado com sucesso!');
          onNovoAluno();
          setTimeout(() => { onFimEdicao(); setMensagem(''); }, 1500);
        })
        .catch(err => setMensagem(err.response?.data?.error||'Erro cadastrar.'));
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      {/* Nome */}
      <div>
        <label>Nome Completo:</label>
        <input value={nome} onChange={e=>setNome(e.target.value)} required className="w-full" />
      </div>
      {/* RA e Box */}
      <div className="grid grid-cols-2 gap-4">
        <div>
          <label>RA:</label>
          <input value={ra} onChange={e=>setRa(e.target.value.replace(/\D/g,'').slice(0,9))} maxLength={9} required className="w-full" />
        </div>
        <div>
          <label>Box:</label>
          <input value={box} onChange={e=>setBox(e.target.value.replace(/\D/g,'').slice(0,3))} maxLength={3} className="w-full" />
        </div>
      </div>

      {/* Período */}
      <div>
        <label className="block font-medium mb-1">Período:</label>
        <select
          className="w-full border rounded px-3 py-2"
          value={periodoId}
          onChange={e => setPeriodoId(e.target.value)}
          required
        >
          <option value="">Selecione um período</option>
          {periodos.map(p => (
            <option key={p.id} value={String(p.id)}>
              {p.nome} ({p.turno})
            </option>
          ))}
        </select>
      </div>

      {/* Login */}
      <div>
        <label className="block font-medium mb-1">Login:</label>
        <input
          type="text"
          className="w-full border rounded px-3 py-2"
          value={usuario}
          onChange={e => setUsuario(e.target.value)}
          required
        />
      </div>

      {/* Senha */}
      <div>
        <label className="block font-medium mb-1">
          {alunoEditando ? 'Nova senha (opcional)' : 'Senha:'}
        </label>
        <div className="relative">
          <input
            type={showSenha ? 'text' : 'password'}
            className="w-full border rounded px-3 py-2 pr-10"
            value={senha}
            onChange={e => setSenha(e.target.value)}
            required={!alunoEditando}
          />
          <button
            type="button"
            className="absolute inset-y-0 right-0 px-3 text-sm"
            onClick={() => setShowSenha(prev => !prev)}
          >
            {showSenha ? 'Ocultar' : 'Mostrar'}
          </button>
        </div>
      </div>

      {/* Permissão */}
      <div>
        <label className="block font-medium mb-1">Permissão:</label>
        <select
          className="w-full border rounded px-3 py-2"
          value={role}
          onChange={e => setRole(e.target.value)}
        >
          <option value="aluno">Aluno</option>
          <option value="recepcao">Recepção</option>
        </select>
      </div>

      {/* Botões */}
      <div className="flex gap-4 mt-6">
        <button
          type="submit"
          className="bg-[#1A1C2C] text-white font-semibold py-2 px-6 rounded-full hover:bg-[#3B4854]"
        >
          {alunoEditando ? 'Atualizar' : 'Cadastrar'}
        </button>
        {alunoEditando && (
          <button
            type="button"
            className="bg-[#DA3648] text-white font-semibold py-2 px-6 rounded-full hover:bg-[#BC3140]"
            onClick={onFimEdicao}
          >
            Cancelar
          </button>
        )}
      </div>

      {mensagem && (
        <p
          className={`mt-4 ${
            mensagem.toLowerCase().includes('sucesso')
              ? 'text-green-600'
              : 'text-red-600'
          }`}
        >
          {mensagem}
        </p>
      )}
    </form>
  );
}

export default FormAluno;
